export type M3ShapeGroupNode = M3NodeTrait<"SHAPE_GROUP"> & M3GroupTrait & {
    /**
     * booleanOperation: 形状组合或布尔运算模式。
     */
    booleanOperation?: "NONE" | "UNION" | "DIFFERENCE" | "INTERSECT" | "XOR";
};

